// Storage abstraction contract
// Files: src/lib/storage/index.ts, src/lib/storage/storage.native.ts, src/lib/storage/storage.web.ts, src/lib/storage/secureStorage.ts, src/lib/storage/secureStorage.native.ts, src/lib/storage/secureStorage.web.ts

// Import from '@/lib'
export interface Storage {
  getItem(key: string): Promise<string | null>;
  setItem(key: string, value: string): Promise<void>;
  removeItem(key: string): Promise<void>;
  clear(): Promise<void>;
}

export interface SecureStorage {
  getItem(key: string): Promise<string | null>;
  setItem(key: string, value: string): Promise<void>;
  removeItem(key: string): Promise<void>;
  clear(): Promise<void>;
}

export const storage: Storage;
export const secureStorage: SecureStorage;

// Behavior
// - Native storage uses @react-native-async-storage/async-storage API shape for general key/value data.
// - Web storage uses localStorage with try/catch guards for restricted/private contexts.
// - Native secure storage uses expo-secure-store for sensitive values.
// - Web secure storage falls back to localStorage and emits warnings about reduced security.
// - All implementations are async and never throw on get/remove unless caller needs explicit write/clear error handling.
